var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이 커다란 게... 네 친구라고?","JPN":"この大きいのが……君の友だち？","ENG":"That big thing... that's your friend?","TWN":"這麼大的東西……是你的朋友？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응. 이름은 기억 안 나지만.","JPN":"うん。名前は覚えてないけど。","ENG":"Yeah. I don't remember its name, though.","TWN":"嗯，但名字我想不起來了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"움직이지 않는데... 괜찮은 건가?","JPN":"動かないけど……大丈夫なの？","ENG":"It's not moving... is it all right?","TWN":"它不會動……沒關係嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"알 수 있어. 그냥 잠들어 있는 거 뿐이야.","JPN":"分かるんだ。今はただ眠ってるだけ。","ENG":"I can tell. It's just asleep.","TWN":"它知道，只是睡著了而已。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"근데, 깨어나기 싫은가 봐요.","JPN":"でも、起きたくないみたい。","ENG":"But... I guess it doesn't want to wake up.","TWN":"不過它好像不想醒來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"깨어나기 싫은 거라고?","JPN":"起きたくない？","ENG":"It doesn't want to wake up?","TWN":"不想醒來？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"낙원은 모두의 소망을 이뤄주는 곳.","JPN":"楽園はみんなの願いを叶えてくれる場所。","ENG":"The Promised Land is a place that grants everyone's wishes.","TWN":"樂園是實現每個人願望的地方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"누군가에겐 휴식이 가장 큰 소망일 수도 있는 법이지.","JPN":"誰かには休むことが最も大きな願いなのかもしれないわ。","ENG":"For some people, rest might be their greatest wish.","TWN":"對某些人來說，最大的願望可能是休息呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그럼, 클라라의 친구는 원하던 잠을 낙원에서 실컷 자고 있는 거구나.","JPN":"じゃあ、クララの友だちは楽園で思う存分眠っているわけか。","ENG":"Then Clara's friend must be getting all the sleep it ever wanted here in the Promised Land.","TWN":"所以克拉拉的朋友就在樂園裡盡情睡覺啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"깨워서 같이 놀고 싶지는 않아?","JPN":"起こして一緒に遊びたいとは思わないの？","ENG":"Don't you want to wake it up and play together?","TWN":"你不想叫醒它一起玩嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"괜찮아요. 노는 건 둘 다 즐거워야 하는걸.","JPN":"大丈夫。遊ぶなら二人とも楽しくなくちゃ。","ENG":"It's all right. Playing should be fun for both of us.","TWN":"沒關係，玩樂要雙方都快樂才有意義。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"지금도 전부 다 듣고 있을 테니까. 나중에 불러도 돼.","JPN":"今も全部聞いているはずだから。後で呼んでもいいの。","ENG":"It can hear everything even now. I can call it later.","TWN":"它現在也都聽得到，以後再叫它就好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"나하고 친구, 모두가 원할 때.","JPN":"クララと友だち、二人とも遊びたい時にね。","ENG":"When both my friend and I want to.","TWN":"等到我和朋友都想這麼做的時候。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그럼.","JPN":"じゃあ。","ENG":"Then.","TWN":"好啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"친구가 깨어날 때까지는 나랑 같이 놀까?","JPN":"友だちが起きるまで、私と遊ぶ？","ENG":"Until your friend wakes up, want to play with me?","TWN":"朋友醒來前，我先和你一起玩吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"그래도 돼?","JPN":"いいの？","ENG":"Would that be all right?","TWN":"可以嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"너만 괜찮다면.","JPN":"君がよければ。","ENG":"If you're all right with it.","TWN":"只要你可以。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"...응.","JPN":"……うん。","ENG":"...Okay.","TWN":"……嗯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"그치만, 떠나고 싶으면 말해도 돼요.","JPN":"でも、帰りたくなったらそう言って。","ENG":"But if you ever want to leave, you can say so.","TWN":"但如果你想離開，可以告訴我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"떠나고 싶으면...?","JPN":"帰りたくなったら……？","ENG":"If I want to leave...?","TWN":"想離開……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"별로, 그러고 싶어질 일은 없을 것 같긴 한데...","JPN":"別に、そうなることはないと思うけど……","ENG":"I don't think I'll feel that way...","TWN":"我應該不會有想離開的理由……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"약속 때문에 떠나고 싶어도 떠나지 못하는 건, 슬픈 일이니까.","JPN":"約束のせいで帰りたくても帰れないのは、悲しいことだから。","ENG":"Because wanting to leave but being unable to because of a promise is sad.","TWN":"如果因為約定讓你想離開卻走不了，也是件很悲傷的事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래.","JPN":"分かった。","ENG":"Okay.","TWN":"是啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"같이 놀자. 우리 중 누군가 떠나고 싶을 때까지.","JPN":"一緒に遊ぼう。私たちのうちの誰かが帰りたくなるまで。","ENG":"Let's play together. Until one of us wants to leave.","TWN":"我們一起玩到有人想離開吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그때까지는 편히 쉬고 있어.","JPN":"だから、それまではゆっくり休んでて。","ENG":"Until then, rest easy.","TWN":"在那之前就好好休息。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"클라라의 친구.","JPN":"クララの友だち。","ENG":"Clara's friend.","TWN":"克拉拉的朋友。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L35_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아까부터 말이 없구나. 에클레시아.","JPN":"さっきから一言も話さないね、エクレシア。","ENG":"You've been quiet for a while, Ecclesia.","TWN":"你從剛才就沒說話呢，艾可露西亞。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"혹시, 내 요리가 맛이 없어서 그러니?","JPN":"もしかして、僕の料理がまずいのかい？","ENG":"Is it because my cooking isn't your taste?","TWN":"是不是覺得我的料理不好吃？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"예?!","JPN":"えっ！？","ENG":"Huh?!","TWN":"啊？！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아뇨, 그럴 리가요! 아버지의 감자 요리가 세상에서 제일로 맛있사옵니다!","JPN":"いいえ、まさか！　お父様のポテト料理が世界で一番美味しいです！","ENG":"No, of course not! Father's potato dish is the most delicious thing in the world!","TWN":"不，怎麼可能！父親的馬鈴薯料理是世界上最好吃的！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"보셔요! 이런 맛있는 건 금방이라도...!","JPN":"ご覧ください！　これほど美味しいものはすぐに……！","ENG":"See? Something this delicious will be gone in no time...!","TWN":"看好了！這麼好吃的東西，我一下……！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"물은 여기 있어.","JPN":"はい、お水。","ENG":"Here's some water.","TWN":"水在這裡。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"켁, 켈록 콜록-","JPN":"けっ、ゲホゲホ……","ENG":"*Cough* *Cough!*","TWN":"咳、咳咳－"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...감사합니다.","JPN":"……ありがとうございます。","ENG":"...Thank you.","TWN":"……謝謝。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"거 보렴.","JPN":"ほらね。","ENG":"See?","TWN":"看吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아버지의 예언은 틀린 적이 없단다.","JPN":"僕の予言は外れたことがない。","ENG":"Father's prophecies have never been wrong.","TWN":"父親的預言從未出錯。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"크흠...","JPN":"ゴホン……","ENG":"Ahem...","TWN":"咳……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그 외지인 때문이니?","JPN":"あのよそ者のことかい？","ENG":"Is it because of that outsider?","TWN":"是因為那個外地人嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그렇게 다친 사람은 처음 보았습니다.","JPN":"あんなに怪我をした人、初めて見ました。","ENG":"I have never seen someone so badly injured before.","TWN":"我還是第一次看到傷得這麼重的人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"괜찮을지 걱정이 되옵니다.","JPN":"大丈夫か心配でございます。","ENG":"I'm worried whether she'll be all right.","TWN":"我真的很擔心她呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"큰 싸움을 치르고 온 모양이지. 하지만 머잖아 괜찮아질 거다.","JPN":"激しい戦いをして来たのだろう。だが、すぐに良くなるはずだよ。","ENG":"It seems she came here after a great battle. But she'll be fine before long.","TWN":"看來她歷經了一場大戰，不過不久就會沒事了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원이 그녀를 받아들였으니까.","JPN":"楽園は彼女を受け入れたのだから。","ENG":"The Promised Land has accepted her, after all.","TWN":"樂園已經接納她了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...예.","JPN":"……はい。","ENG":"...Yes.","TWN":"……是。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원에서는 모두가 소망을 이루어 행복할 테니 말이지요.","JPN":"楽園では皆が願いを叶え、幸せなはずですからね。","ENG":"In the Promised Land, everyone will have their wishes fulfilled and be happy.","TWN":"在樂園，每個人都能實現願望、獲得幸福。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그러고 보니, 오늘 수확한 양식을 그 사람에게 전해주는 걸 깜빡했구나.","JPN":"そういえば、今日収穫した食料をあの人に渡すのを忘れていたな。","ENG":"Come to think of it, I forgot to bring the food we harvested today to her.","TWN":"這麼說來，我忘了把今天收成的食物帶給她。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"지금쯤 배가 고플지도 모르겠어.","JPN":"今頃お腹を空かしているかもしれない。","ENG":"She might be hungry by now.","TWN":"她現在應該餓了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"앗.","JPN":"あっ。","ENG":"Ah.","TWN":"啊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저에게 맡겨주시지요. 전하겠습니다.","JPN":"わたくしにお任せください。お渡ししてまいります。","ENG":"Please leave it to me. I'll take it to her.","TWN":"那就交給我吧，我去拿給她。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그래주겠니?","JPN":"そうしてくれるかい？","ENG":"Would you?","TWN":"可以嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그럼, 해 저물기 전에 돌아오겠사옵니다!","JPN":"では、日が暮れる前に戻ってまいります！","ENG":"I'll be back before sunset!","TWN":"當然囉，我會在天黑前回來！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"과일을 따러 간다고?","JPN":"果物を収穫しに行くの？","ENG":"You're going to pick fruit?","TWN":"你要去摘水果？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응, 농장으로.","JPN":"うん、農場に。","ENG":"Yeah, at the farm.","TWN":"嗯，去農場那邊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"거기 가면 달콤한 거 잔뜩 있어. 쓴맛 나는 약초도 키워요.","JPN":"そこに行けば甘いものがいっぱいあるよ。苦い味の薬草も育ててるの。","ENG":"If you go there, there's lots of sweet stuff. They grow bitter herbs too.","TWN":"那裡有很多甜的水果，也有種很苦的藥草。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 농장이란 거... 주인이 있지 않아? 멋대로 가져가도 될까?","JPN":"その農場って……主がいるんじゃない？　勝手に持ち帰って大丈夫なの？","ENG":"That farm... Doesn't it have an owner? Is it okay to just take things?","TWN":"農場的話……應該有主人吧？可以隨便拿嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"따나는 친절해. 많이 가져가도 괜찮댔어.","JPN":"タナは優しいの。いっぱい持って帰ってもいいんだって。","ENG":"Dana is kind. She said it's fine to take a lot.","TWN":"搭娜很親切，她說拿多少都沒關係。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"정말 큰 농장이구나. 언덕마다 다른 과일나무가 심어져 있어.","JPN":"本当に広い農場ね。丘ごとに違う果物が植えられているわ。","ENG":"It's quite a large farm. Different fruit trees are planted on every hill.","TWN":"農場真大啊，每個山丘都種著不同的果樹。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"여실히 익었구나. 마치 누가 따가기만 기다리는 것처럼.","JPN":"よく熟れているわね。まるで誰かが収穫してくれるのを待っているみたいだわ。","ENG":"They're fully ripe. As if they're just waiting for someone to pick them.","TWN":"果實都熟了，就像在等人來摘一樣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그러게요.","JPN":"本当に。","ENG":"I know.","TWN":"這樣啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"땅이 얼마나 좋길래 이렇게 열매가 많은 거지?","JPN":"こんなにたくさん実るなんて、相当土地が肥えているんじゃないかな。","ENG":"How good must the soil be to produce so much fruit?","TWN":"這裡的土壤到底有多好，才會有這麼多果實？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RITA_ANAP_NULL_QM","text":{"KOREA":"낙원의 나무에선 매일 아침마다 과실이 열린다.","JPN":"楽園の木には、毎朝果物が実る。","ENG":"The trees of the Promised Land bear fruit every morning.","TWN":"樂園的樹每天早晨都會結果。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L34_1","type":"dialog","speaker":"RITA_ANAP_NULL_QM","text":{"KOREA":"그래서 이곳 주민들은 날이 밝으면 수확을 하고, 점심엔 수확한 것들로 만찬을 즐기지.","JPN":"だからここの住民は夜が明けたら収穫して、昼食は収穫したものが食卓を飾るんだ。","ENG":"So the residents harvest them at dawn and enjoy a feast from the harvest at noon.","TWN":"所以居民天亮後就會來採收，中午就吃採收的東西。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"오, 저 아가씨가 이 농장의 주인인가 보구나.","JPN":"あら、あのお嬢さんがこの農場の主のようね。","ENG":"Oh, that lady must be the owner of this farm.","TWN":"哦，那位小姐是這座農場的主人吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아... 그럼 당신이 따나 씨?","JPN":"あ……じゃあ、あなたがタナさん？","ENG":"Um... you must be Dana?","TWN":"啊……那你就是搭娜嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"RITA_ANAP_NULL_QM","text":{"KOREA":"클라라가 데려온 손님인가 보군.","JPN":"クララが連れてきた客か。","ENG":"You must be the guests Clara brought.","TWN":"看來你是克拉拉帶來的客人吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RITA_ANAP_NULL_QM","text":{"KOREA":"내 이름은 다이나다. 날 그렇게 부르는 건 그 꼬마 밖에 없으니까.","JPN":"私の名前はダイナ。タナと呼んでいるのはあのガキだけだからな。","ENG":"My name is Daina. That little one is the only one who calls me that.","TWN":"我叫黛娜，只有那小傢伙會那樣叫我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...어?","JPN":"……あれ？","ENG":"...Huh?","TWN":"……咦？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"그 여자의 머리칼은 자신이 해치고 나온 무성한 나뭇잎을 닮아 있었다.","JPN":"女の髪は、自分がここに来るまでかき分けてきた生い茂った葉に似ていた。","ENG":"Her hair resembled the lush leaves she had brushed aside while walking through the grove.","TWN":"她的頭髮像她砍下的茂密樹葉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"그것을 본 순간, 뜻 모를 감정이 솟구친다.","JPN":"それを見た瞬間、得体の知れない感情がこみ上げた。","ENG":"The moment I saw it, an inexplicable emotion surged up.","TWN":"看到這一幕，我的心中湧起莫名的情感。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"비명과 희열이라는... 익숙한 색에 담긴 낯선 의미.","JPN":"悲鳴と喜びという……見慣れた色に込められたなじみのない意味。","ENG":"A strange meaning contained within familiar colors... the colors of screams and exhilaration.","TWN":"悲鳴與喜悅……熟悉的顏色混雜著陌生的意義。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"나는 그것의 의미가 무엇인지 알아내기 위해,","JPN":"私はそれが何を意味するのかを探り出すために、","ENG":"To find out what that meaning was,","TWN":"我為了搞清楚這個意義，"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"이성 깊은 곳에 묻혀있던 지저분한 기억 한 조각을 거칠게 끄집어 냈다.","JPN":"理性の奥底に埋められていた汚い記憶の片鱗を荒々しく取り出した。","ENG":"I roughly dragged out a filthy fragment of memory buried deep within my mind.","TWN":"粗暴地從理智深處挖出了那片混亂的記憶碎片。"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신 이름이... 다이나라고?","JPN":"あなたの名前が……ダイナ？","ENG":"Your name... is Daina?","TWN":"你叫……黛娜？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうだ。","ENG":"That's right.","TWN":"是啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"그리고 네 이름은 레아 슈나이더겠지.","JPN":"お前の名前はレア・シュナイダーだな。","ENG":"And you must be Leah Schneider.","TWN":"你應該是蕾亞．修奈德吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"나는...","JPN":"私は……","ENG":"I–","TWN":"我……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...틀려.","JPN":"……違う。","ENG":"...No.","TWN":"……錯了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신에게 난 그런 이름이 아니야. 내 진짜 이름은...","JPN":"あなたにとっての私はその名前じゃない。私の本当の名前は……","ENG":"That's not who I am to you. My real name is–","TWN":"對你來說，我不叫那個名字。我的真名是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"낙원에선 무엇이든 될 수 있지.","JPN":"楽園では何にでもなれる。","ENG":"In the Promised Land, you can be anything.","TWN":"在樂園，可以成為任何人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"네가 레아 슈나이더인 걸 부정하고 다른 이름을 내밀어도, 딱히 달라질 건 없다는 뜻이야.","JPN":"お前がレア・シュナイダーだってことを否定して違う名前を名乗っても、何かが変わることはないってことだ。","ENG":"Even if you deny being Leah Schneider and offer another name instead, nothing would really change.","TWN":"即便你否認叫蕾亞．修奈德，換個名字也不會有什麼不同。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이미 벌어진 일을 돌이킬 수 없단 건 알고 있어.","JPN":"すでに起きたことはどうしようもないって分かってる。","ENG":"I know that what's already happened can't be undone.","TWN":"我知道，已發生的事無法復原。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 변하는 게 없더라도, 숨겨선 안되는 게 있으니까.","JPN":"でも変わることはないとしても、隠してはいけないものはあるから。","ENG":"But even if nothing changes, there are things that shouldn't be hidden.","TWN":"但即便沒法改變，也有不能隱藏的東西。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"우린 피차 죄를 지고 살아갈 운명이었다.","JPN":"私たちはお互い罪を犯しながら生きる運命だった。","ENG":"We were both fated to live with our sins.","TWN":"我們注定背負著罪孽活下去。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"나 역시 수많은 피를 손에 묻혔고, 그걸 변명할 생각은 없어.","JPN":"私の手も数えきれない程の血で染まっているし、それについて言い訳するつもりはない。","ENG":"I, too, have stained my hands with the blood of countless lives. And I have no intention of making excuses for it.","TWN":"我的雙手也沾染著無數鮮血，我也不打算辯解。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만... 우리 모두 이 자리에 살아 숨 쉬고 있네.","JPN":"でも……私たち二人ともここで生きている。","ENG":"But... we're all still alive here.","TWN":"但……我們都在這裡呼吸著。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"죄라는 건, 섭리와 함께 공존하는 거다. 이미 벌어진 일은 돌이킬 수 없다는 섭리...","JPN":"罪というものは、摂理とともにあるもの。すでに起きたことは取り戻せないという摂理……","ENG":"Sin coexists with the laws of the world. The law that what's already happened can't be undone...","TWN":"罪與法則共存，已發生的事無法復原的法則……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"하지만 죽음이 없는 이곳에선 그런 섭리도 통하지 않아.","JPN":"だが、死のないここでそんな摂理も通じない。","ENG":"But in this place where death doesn't exist, even that law doesn't apply.","TWN":"但這裡沒有死亡，法則也失去意義。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"그러니 악인과 선인을 구분하는 것만큼 무의미한 일도 없지.","JPN":"だから悪人と善人を見分けることほど無意味なことはないんだ。","ENG":"So there is nothing more meaningless than distinguishing between the wicked and the righteous.","TWN":"因此區分善惡，也毫無意義。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"그저 자신이 죽인 사람에게 속죄하며, 그것에 만족하는 네 자신만이 있을 뿐.","JPN":"ただ自分が殺した人に償い、それに満足するお前自身がいるだけだ。","ENG":"There is only yourself, atoning to those you killed and finding satisfaction in that.","TWN":"只剩下向自己殺的人贖罪，並為此感到滿足的自己。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그래.","JPN":"……そうだね。","ENG":"...Right.","TWN":"……嗯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신 말처럼 여기서 속죄하는 건 아무 의미가 없을지도 모르겠네.","JPN":"あなたの言うとおり、ここで罪を償うのは何の意味もないのかもしれないね。","ENG":"Just as you said, perhaps atonement here truly means nothing.","TWN":"就像你說的，贖罪這件事或許在這裡毫無意義。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그럼 이곳에서 당신과 난... 어떤 관계가 되는 거지?","JPN":"じゃあここでのあなたと私って……どんな関係になるの？","ENG":"Then here in this place... what kind of relationship would you and I have?","TWN":"那麼我和你在這裡……會成為什麼關係呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"글쎄. 그건 각자의 판단에 달려있겠지.","JPN":"さあな。それはそれぞれの判断次第だろう。","ENG":"Who knows. That depends on each person's judgment.","TWN":"這個嘛，就看各自的判斷了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"평범한 세상의 인간들처럼.","JPN":"普通の世界の人間たちがそうであるように。","ENG":"Just like people in an ordinary world.","TWN":"就像平凡世界的人類一樣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"클라라가 좋아하는 딸기는 동쪽 고개 너머에 있어.","JPN":"クララが好きなイチゴは東の峠の向こうにある。","ENG":"The strawberries Clara likes are beyond the eastern ridge.","TWN":"克拉拉愛的草莓，在東邊的山丘。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"원하는 만큼 얼마든지 따가도 돼.","JPN":"いくらでも持って行くといい。","ENG":"Pick as many as you want.","TWN":"你想摘多少就摘多少。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어떤 선택을 해도 의미가 없는 거라면...","JPN":"どんな選択をしても意味がないなら……","ENG":"If every choice here is meaningless...","TWN":"如果任何選擇都沒有意義……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이런 낙원이 존재하는 이유는 뭐지?","JPN":"こんな楽園が存在する理由は何？","ENG":"Then why does a place like the Promised Land even exist?","TWN":"這種樂園存在的原因是什麼呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"그 누구의 선택도 필요로 하지 않기 때문에-","JPN":"誰の選択も必要としないからこそ……","ENG":"Because it requires no one's choice...","TWN":"因為這裡不需要任何人的選擇—"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"비로소 낙원이 되는 거다.","JPN":"楽園になるんだ。","ENG":"Only then does it become the Promised Land.","TWN":"所以才能成為真正的樂園。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"딸기, 오늘도 잔뜩 땄어요.","JPN":"イチゴ、今日もいっぱい摘んだよ。","ENG":"I picked lots of strawberries again today.","TWN":"今天也摘了一大堆草莓。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그래. 정말 맛있어 보이는구나.","JPN":"そうね。本当に美味しそう。","ENG":"Yes. They look very delicious.","TWN":"嗯，看起來真的很美味。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"아- 해.","JPN":"あーんして。","ENG":"Here. Say, \\"ah.\\"","TWN":"啊—好棒。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아-","JPN":"あーん。","ENG":"Ah...","TWN":"啊—"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"맛있어?","JPN":"美味しい？","ENG":"Is it good?","TWN":"好吃嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L45_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"후후, 그럼. 클라라가 따준 딸기가 내가 딴 것보다 달구나.","JPN":"ふふ、もちろんよ。クララが摘んだイチゴは、私のものより甘いわね。","ENG":"Hehe, of course. The strawberries Clara picked are sweeter than the ones I picked.","TWN":"呵呵，當然囉。克拉拉摘的草莓，比我摘的還甜。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"이건 스무디로 만들래. 더 맛있을 거야.","JPN":"これはスムージーにするの。もっと美味しくなるよ。","ENG":"I'll make these into a smoothie. It'll taste even better.","TWN":"我要做成果昔，那樣會更好吃。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"클라라가 만들어주는 거니? 벌써 기대가 되는 걸?","JPN":"クララが作ってくれるのかしら？　楽しみね。","ENG":"You'll make it, Clara? I'm already looking forward to it.","TWN":"是克拉拉做的嗎？我已經開始期待了呢。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응!","JPN":"うん！","ENG":"Okay!","TWN":"嗯！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"응?","JPN":"あら？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"집 앞에 누가 있구나.","JPN":"家の前に誰かがいるわ。","ENG":"Someone's in front of the house.","TWN":"有人在家門口啊。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"그러게. 코오- 자고 있어.","JPN":"そうだね。ぐーぐーしてる。","ENG":"You're right. She's asleep.","TWN":"對啊，在呼呼—睡覺。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"코오...","JPN":"グー……","ENG":"Zzz...","TWN":"呼呼……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저 아이는...?","JPN":"あの子は……？","ENG":"Is that...?","TWN":"那孩子……？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"설마... 에클레시아?","JPN":"まさか……エクレシア？","ENG":"It can't be... Ecclesia?","TWN":"難道是……艾可露西亞？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"으, 으음?","JPN":"う、うーん？","ENG":"M-mm?","TWN":"嗯、嗯？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"앗...? 아앗!","JPN":"あ……？　ああっ！","ENG":"Ah...? Aah!","TWN":"啊……！？啊啊！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"못 볼 꼴을 보였습니다! 남의 집 문 앞에서 잠들다니!","JPN":"だらしないところをお見せしてしまいました！　人様のお宅の前で眠り込んでしまうなんて！","ENG":"I have made a disgrace of myself! Falling asleep in front of someone else's house!","TWN":"我好丟臉！竟然在別人家門口睡著了！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저기... 그렇게 빤히 바라보시면 부끄럽나이다.","JPN":"あの……そう見つめられると恥ずかしいです。","ENG":"Um... if you stare at me like that, I become embarrassed.","TWN":"那個……你一直盯著我看，我會害羞啦。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...아, 미안.","JPN":"……あ、ごめん。","ENG":"...Ah, sorry.","TWN":"……啊，抱歉。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 아는 사람이랑 비슷해 보여서.","JPN":"私の知り合いと似てたから。","ENG":"You just resemble someone I know.","TWN":"只是你長得很像我認識的人。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"혹시 이름이 어떻게 돼?","JPN":"あの、名前は？","ENG":"May I ask your name?","TWN":"你叫什麼名字？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"에클레시아... 라고 하옵니다.","JPN":"エクレシア……と申します。","ENG":"Ecclesia... that is my name.","TWN":"我叫……艾可露西亞。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...왜 그렇게 어려진 거야?","JPN":"……どうしてそんなに幼くなっちゃったの？","ENG":"...Why have you become so young?","TWN":"……為什麼變這麼小了？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"예? 그게 무슨 말씀이시온지.","JPN":"はい？　それはどういうことでございますか。","ENG":"Pardon? I'm not sure what you mean.","TWN":"嗯？那是什麼意思？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아무 때나 잠들어버리는 버릇이 있다고?","JPN":"時を選ばず眠ってしまう癖がある？","ENG":"You have a habit of falling asleep anywhere?","TWN":"你說你有隨時睡著的習慣？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...예.","JPN":"……はい。","ENG":"...Yes.","TWN":"……是。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"잠이 남들보다 많은 편은 아니오나, 정신 차려보면 아무 데서나 잠들어 있사옵니다.","JPN":"他の人と比べて眠気が強いというわけでもないのですが、気がつくと色んなところで眠っているのです。","ENG":"I do not believe I sleep more than others, but whenever I come to my senses, I find that I have fallen asleep somewhere.","TWN":"雖然我沒有很愛睡覺，但只要一不注意就會在任何地方睡著。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"아무 데서나 자면, 그게 잠이 많은 거 아냐?","JPN":"色んなところで寝ちゃうなら、眠たいってことじゃない？","ENG":"If you fall asleep anywhere, doesn't that mean you sleep a lot?","TWN":"在任何地方都能睡著，這不就是很愛睡覺嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그런 것인지요?","JPN":"そうなのですか？","ENG":"Is that so?","TWN":"是這樣嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그건 그렇고.","JPN":"それはそうとして。","ENG":"Anyway.","TWN":"算了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신, 정말로 내가 누군지 모르겠어?","JPN":"あなた、本当に私のこと知らない？","ENG":"Do you really not know who I am?","TWN":"你真的不認識我嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"네, 오늘 처음 보았습니다.","JPN":"はい、今日初めてお目にかかりました。","ENG":"No. Today is the first time I've met you.","TWN":"對，我們今天第一次見面。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그런데, 어른께서 저를 존대하시니... 저도 같은 어른이 된 것 같아 두근두근하옵니다, 헤헤.","JPN":"ところで、年上の方から「あなた」と呼ばれますと……わたくしも大人になったようでドキドキいたします、へへっ。","ENG":"But since you speak to me so respectfully... it makes my heart flutter as if I, too, have become a grown-up. Hehe.","TWN":"不過，你對我的態度……讓我覺得自己也變成大人了，心裡怦怦跳呢。嘿嘿。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"겉모습만 변한 게 아니야. 머릿속까지 영락없는 아이처럼 변했어.","JPN":"外見だけじゃない。頭の中まで完全に子どもになってる。","ENG":"It's not just her appearance that changed. Her mind has become that of a complete child.","TWN":"不只是外貌，連頭腦也完全變成孩子了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어떻게 된 거지? 일종의 침식 현상? 시간이 뒤틀리기라도 한 건가?","JPN":"どういうこと？　一種の侵食現象？　時間が歪みでもしたっていうの？","ENG":"What happened to her? Some kind of Counterside Effect? Did time itself twist?","TWN":"這是怎麼回事？是某種侵蝕現象？還是時間被扭曲了？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저기, 레아 님.","JPN":"あの、レア様。","ENG":"Um, Ms. Leah.","TWN":"那個，蕾亞小姐。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"응?","JPN":"うん？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"상처 좀 살펴봐도 되겠습니까?","JPN":"傷を診せていただいてもよろしいでしょうか？","ENG":"May I examine your wound?","TWN":"我可以檢查一下傷口嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"치료가 잘 된 것인지, 확인하겠사옵니다.","JPN":"しっかり治療ができているか、確認いたします。","ENG":"I wish to confirm whether it has healed properly.","TWN":"我想確認治療是否有效。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이렇게 하면... 잘 보여?","JPN":"こうすれば……よく見える？","ENG":"Can you see it well.. if I do this?","TWN":"這樣……可以看到嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"으음...","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"이번엔 벌어지지 않고 잘 봉합 됐으니 안심하소서.","JPN":"今回は開かずにちゃんと縫合されておりますので、ご安心を。","ENG":"This time it has closed well without reopening, so please rest assured.","TWN":"你放心，這次沒有再裂開，很順利癒合了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"붕대만 갈 수 있게 허락해주시렵니까?","JPN":"包帯を替えてもよろしいでしょうか？","ENG":"Would you permit me to change the bandage?","TWN":"可以讓我換繃帶嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그렇게 해.","JPN":"そうして。","ENG":"Go ahead.","TWN":"好。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"처음엔 놀랐습니다.","JPN":"最初は驚きました。","ENG":"At first, I was quite surprised.","TWN":"我一開始嚇到了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아버지에게 치료하는 법을 배워두긴 했지만, 낙원에서 다친 사람은 처음 보았습니다.","JPN":"お父様から治療する方法を教わってはおりましたが、楽園で怪我した方を見るのは初めてでしたので。","ENG":"Father taught me how to treat injuries, but this is the first time I have seen someone injured in the Promised Land.","TWN":"雖然跟父親學過治療的方法，但我還是第一次在樂園看到受傷的人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"처음 봤다고? 여기 사람들도 살다 보면 종종 다치고 그러지 않아?","JPN":"初めてって？　ここの人だって、生活してたら怪我することくらいあるでしょう？","ENG":"The first time? Don't people here sometimes get hurt while living their lives?","TWN":"第一次？這裡的人也不會受傷嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원에선 하루가 지나면, 내일이 아닌 같은 하루가 돌아옵니다.","JPN":"楽園では一日が過ぎると、明日ではなく同じ一日が始まるのです。","ENG":"In the Promised Land, when a day passes, the same day returns rather than tomorrow.","TWN":"在樂園裡，每一天都是同一天。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"오늘 딴 열매가 다음날 그 자리에 열려있듯, 다친 사람은 상처가 남지 않습니다.","JPN":"今日収穫した実が明日には同じ場所にまた実っているように、怪我人に傷は残りません。","ENG":"Just as the fruit picked today appears again in the same place the next day, injuries do not remain.","TWN":"今天摘下的果實，在隔天還會原地結出新果，受傷的人也不會留下傷痕。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아마도 레아 님의 상처가 남아있는 것은, 레아 님이 낙원 밖에서 다쳤기 때문이라 사료되옵니다만...","JPN":"恐らくレア様の傷が残っている理由は、レア様が楽園の外で怪我をされたせいであると思われますが……","ENG":"Perhaps the reason your wounds remain, Lady Leah, is because you were injured outside the Promised Land...","TWN":"所以蕾亞小姐會有傷口，是因為你是在樂園外受的傷吧……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"분명 이 상처가 다 낫고 나면, 레아 님도 다른 주민들처럼 좋아질 것이옵니다.","JPN":"きっとこの傷が治れば、レア様も他の住民のようによくなるでしょう。","ENG":"But once these wounds heal completely, I believe you will become like the other residents as well.","TWN":"等傷口好了，你也會像其他居民一樣沒事的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...다른 주민들처럼 된다라.","JPN":"……他の住民のように、ね。","ENG":"...Like the other residents.","TWN":"……變得像其他居民一樣啊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그런데... 어쩌다 이리 다치게 되신 것이옵니까?","JPN":"ところで……どうしてこんな怪我を？","ENG":"But... how did you become so badly injured?","TWN":"不過……你怎麼傷得這麼重？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"강한 적이랑 싸웠어. 목숨을 걸어야 했지.","JPN":"強い敵と戦ったの。命をかけてね。","ENG":"I fought a powerful enemy. I had to risk my life.","TWN":"我賭上性命，跟很厲害的敵人打架了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"목숨을... 걸고?","JPN":"命を……かけて？","ENG":"Risk your... life?","TWN":"賭上……性命？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그건 어떤 의미이옵니까?","JPN":"それはどういう意味でしょうか？","ENG":"What does that mean?","TWN":"那是什麼意思？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어떤 의미냐니. 그야 죽음을 각오했다는 거지.","JPN":"どういう意味って、死を覚悟したってことだよ。","ENG":"What do you mean? It means I was prepared to die.","TWN":"什麼意思啊，就是做好死亡的覺悟。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이 낙원이란 곳에선 아닐지 몰라도, 보통의 세상에서 목숨은 하나 뿐인 거니까.","JPN":"ここ楽園とやらでは違うかもしれないけど、普通の世界で命は一つだけだからね。","ENG":"The Promised Land might be different, but in an ordinary world a person only has one life.","TWN":"雖然在樂園這裡可能不一定如此。但在普通世界裡，人只有一條性命。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그리고, 나 뿐만 아니라 당신 역시 거기에 있었어.","JPN":"それに、私だけじゃなくあなたもそこにいたよ。","ENG":"And not just me. You were there too.","TWN":"而且不只我，你也在那裡。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"소녀가... 그대와 함께 있었다니?","JPN":"わたくしが……あなたと一緒にいたのですか？","ENG":"I... was with you?","TWN":"我……也和你在一起嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"하지만 전 레아 님을 처음 뵈옵는데.","JPN":"ですが、わたくしとレア様は初対面でございます。","ENG":"But this is the first time I have met you, Ms. Leah.","TWN":"但我是第一次見到蕾亞。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"나도 이게 어떤 상황인진 잘 모르겠어.","JPN":"私もこれがどういう状況なのか分からない。","ENG":"I don't really understand what's going on either.","TWN":"我也不太清楚這是什麼情況。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"왜 죽었어야 할 내가 낙원이라 불리는 곳에서 눈을 떴는지, 당신은 왜 그렇게 어려진 모습으로 내 앞에 나타난 건지.","JPN":"どうして死ぬべきだった私が楽園と呼ばれる場所で目覚めたのか、あなたはどうしてそんなに幼くなった姿で私の前に現れたのか。","ENG":"Why I, who should have died, woke up in a place called the Promised Land, or why you appeared before me looking so young.","TWN":"為什麼本該死去的我，會在這個被稱為樂園的地方醒來，你為什麼會以那麼年輕的樣子出現在我面前。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하지만 분명히 기억하는 건, 우리 둘 다 세상이 멸망하는 걸 막으려고 타기리온이라는 마왕에게 맞섰다는 거야.","JPN":"でもはっきりと覚えてるのは、私たち二人は世界が滅ぶのを阻止するために、タギリオンという魔王に立ち向かったってことだよ。","ENG":"But what I remember clearly is that both of us stood against a Demon Lord named Thagirion to stop the destruction of the world.","TWN":"但我記得很清楚，我們倆都是為了阻止世界毀滅，才去對抗那個叫塔基里翁的魔王。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그럼... 레아 님이 말씀하신 강한 적이 타기리온인 겁니까?","JPN":"では……レア様がおっしゃった強い敵というのはタギリオンのことなのですか？","ENG":"Then... is the powerful enemy you mentioned Thagirion?","TWN":"那麼……蕾亞說的強敵，就是塔基里翁嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 이름은 기억하는거야?","JPN":"その名前は覚えてるの？","ENG":"You remember that name?","TWN":"你記得那個名字嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"<color=#ffd34c>낙원이 있기 전의 세계</color>를 멸망시킨 마왕... 이라는 것은 알고 있습니다.","JPN":"<color=#ffd34c>楽園ができる前の世界</color>を滅ぼした魔王……ということは存じております。","ENG":"I know that the Demon Lord who destroyed the <color=#ffd34c>world before the Promised Land existed</color> was called that...","TWN":"我知道……他是摧毀<color=#ffd34c>樂園出現前的世界</color>的魔王。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"하지만 소녀가 그런 존재와 싸운 기억은 전혀 없사옵니다.","JPN":"ですが、わたくしはそのような存在と戦った覚えはまったくありません。","ENG":"But I have absolutely no memory of fighting such a being.","TWN":"但我完全沒有那種東西和戰鬥的記憶。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"나도 얼마 전까진 몰랐지만... 당신이 살던 세계가 존재하는 전부는 아니야.","JPN":"私もついこの間までは知らなかったんだけど……あなたが住んでいた世界がすべてではないんだよ。","ENG":"Until recently, I didn't know either... but the world you lived in isn't the whole of existence.","TWN":"我直到不久前才知道……你生活的世界並不是全部。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저 너머 어딘가엔 내가 태어난 세계가 있고, 그곳엔 많은 사람들이 살고 있지.","JPN":"その向こうのどこかには私が生まれた世界があって、そこにたくさんの人が住んでいる。","ENG":"Somewhere beyond lies the world where I was born, where many people live.","TWN":"在那邊的某個地方，有我出生的世界、住著很多人。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그리고 마왕 타기리온은 지금 그곳을... 내 고향을 없애려 하고 있어.","JPN":"そして魔王タギリオンは今その世界を……私の故郷を消そうとしてる。","ENG":"And the Demon Lord Thagirion is now trying to destroy that place... My home.","TWN":"而魔王塔基里翁現在正試圖……摧毀我的故鄉。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원 밖, 아무도 살지 않는 동토 너머에 마왕이 있다는 얘긴 들었사옵니다.","JPN":"楽園の外、誰も住んでいない凍土の向こうに魔王がいるという話は聞いております。","ENG":"I have heard that beyond the gelid lands outside the Promised Land, there is a Demon Lord.","TWN":"我聽說在樂園外、無人居住的凍土那邊有魔王。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그치만 다른 멀쩡한 세계가... 그것도 저희 세계를 멸망시킨 자에게 노려지고 있었다는 건 처음 알았습니다.","JPN":"ですが、他に普通の世界が……それもわたくしたちの世界を滅亡させた者に狙われていたということは初めて知りました。","ENG":"But I never knew that another intact world... was also being targeted by the one who destroyed our world.","TWN":"但我也第一次知道……那個完好無缺的世界，也被毀滅我們世界的人盯上了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신은...","JPN":"あなたは……","ENG":"You...","TWN":"你……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"다른 세계가 당신의 세계처럼 되는 걸 막기 위해, 누구보다 오랫동안 타기리온을 쫓아 다녔어.","JPN":"他の世界があなたの世界のようになることを阻止するために、誰よりも長くタギリオンを追っていた。","ENG":"To stop another world from becoming like yours, you chased Thagirion longer than anyone else.","TWN":"為了避免其他世界像你的世界一樣被毀滅，追蹤塔基里翁比任何人都久。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런 당신이 이런 얘길 처음 듣는다는 게 믿기지 않네.","JPN":"そんなあなたが、この話を初めて聞いただなんて信じられないよ。","ENG":"I can't believe that you're hearing this for the first time.","TWN":"這樣的你居然第一次聽到這件事，真讓人難以相信。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"난 어떻게든 당신을 데리고 그 녀석에게 복수할 생각이었는데 말이야.","JPN":"私は何としてでもあなたを連れてあいつに復讐するつもりだったのに。","ENG":"I was planning to take you with me and get revenge on that bastard somehow.","TWN":"我本來想無論如何都要帶你去找那傢伙復仇。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...복수.","JPN":"……復讐。","ENG":"...Revenge.","TWN":"……復仇。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"잃었다고 해서, 꼭 되갚아야만 하는 것이옵니까?","JPN":"失ったからといって、必ずやり返す必要はあるのでしょうか？","ENG":"Just because something was lost, must it always be repaid?","TWN":"失去了，就一定要找回來嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...뭐?","JPN":"……え？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원에선 그 누구와도 싸울 필요가 없습니다.","JPN":"楽園では誰とも戦う必要などありません。","ENG":"In the Promised Land, there is no need to fight anyone.","TWN":"在樂園裡，不需要和其他人戰鬥。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"세계를 멸망시키거나 사람을 해친 악인이 있었다 해도... 미워하는 건 무의미합니다.","JPN":"世界を滅亡させたり、人に害をなした悪人がいたとしても……憎むことに意味がないのです。","ENG":"Even if there was a villain who destroyed worlds or harmed people... hating them is meaningless.","TWN":"即便有毀滅世界或傷害人的壞人……恨他也沒有意義。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"이곳 낙원엔 멸망도, 죽음도 존재하지 않으니까요.","JPN":"ここ、楽園には滅亡も死も存在しないからです。","ENG":"Because here in the Promised Land, there is no destruction and no death.","TWN":"因為在這個樂園，沒有毀滅，也沒有死亡。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"떠오르는 말은 수도 없었지만, 그 무엇도 입 밖으로 낼 수 없었다.","JPN":"たくさんの言葉が頭の中に浮かび上がったけど、何一つ口に出すことはできなかった。","ENG":"There were countless things I wanted to say, yet none of them could leave my mouth.","TWN":"雖然我腦中浮現無數話語，但一句話也說不出口。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"지금껏 누구보다 타기리온을 증오하고, 그녀를 막기 위해 싸워온 사람을...","JPN":"今まで誰よりもタギリオンを憎み、彼女を止めるために戦ってきた人を……","ENG":"To think that I, carrying the memories of Maestra Nequitia...","TWN":"當我意識到說服比任何人都憎恨泰里昂，爲了阻止她而戰鬥的人……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"...마에스트로 네퀴티아라는 기억을 가진 내가 설득하고 있다는 사실에 부딪히자, 말문이 막혔다.","JPN":"……マエストロ・ネキティアという記憶を持つ私が説得しているという事実にぶち当たり、何も言えなくなった。","ENG":"was trying to persuade the very person who had hated Thagirion more than anyone and fought to stop her... I found myself at a loss for words.","TWN":"……竟然是是擁有指揮家．莉奎蒂亞記憶的我……，一時間我說不出話。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"만약 내가 알던 에클레시아라는 사람은 이미 죽었거나, 모든 기억을 잃었다면...","JPN":"もし私の知るエクレシアという人がすでに死んでいたり、すべての記憶を失っているとしたら……","ENG":"If the Ecclesia I once knew has already died, or lost all her memories...","TWN":"如果我記得的艾可露西亞已經死了，或者失去了所有記憶……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"그녀와 같은 얼굴, 같은 이름을 가진 소녀를 다시 이 피투성이의 굴레로 끌어들이는 게 옳은 선택일까?","JPN":"彼女と同じ顔、同じ名前を持つ少女を再びこの血まみれのしがらみに引き込むのは正しい選択なのだろうか？","ENG":"Would it really be right to drag a girl with the same face and name back into that blood-soaked cycle?","TWN":"那麼把一個和她外貌、名字都一樣的女孩再拉回這個血腥的世界，是對的選擇嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"잃어버렸던 모든 것이 다시 품으로 돌아온 낙원에서... 그런 그녀를 차가운 현실로 끌어내야만 하는 걸까?","JPN":"失ってしまったすべてを再び手にいれたこの楽園から……そんな彼女を冷たい現実に引っ張り出す必要があるのだろうか？","ENG":"In the Promised Land, where everything once lost has returned to her embrace... Should I really pull her back into that cold reality?","TWN":"在重拾失去的一切的樂園……我真的需要把她拉回冰冷的現實嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어쩌면, 당신 말이 맞을 지도 몰라.","JPN":"もしかしたら、あなたの言うとおりなのかもしれない。","ENG":"Perhaps you might be right.","TWN":"也許你說得對。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이 낙원이란 곳에선... 타기리온과 싸울 필요가 없을지도 모르겠네.","JPN":"この楽園って場所では……タギリオンと戦う必要がないのかも。","ENG":"In this place called the Promised Land... maybe there's no need to fight Thagirion.","TWN":"在這個樂園……或許不需要和塔基里翁戰鬥。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"소녀는 이만 돌아가보겠사옵니다.","JPN":"わたくし、これで失礼いたします。","ENG":"I should get going.","TWN":"我要先回去了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그러네. 해가 지기 시작했어.","JPN":"そうだね。日が暮れ始めてる。","ENG":"Oh. The sun's beginning to set.","TWN":"啊，天色暗下來了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"곧 밤이 될 테니 같이 집까지 바래다 줄까? 아까처럼 도중에 잠들어버리면 곤란하니까.","JPN":"すぐ夜になるから、家まで送ってあげようか？　さっきみたいに途中で眠っちゃったら困るし。","ENG":"It'll be night soon. Want me to walk you home? It'd be trouble if you fell asleep again on the way like before.","TWN":"馬上就要天黑了，要不要我陪你回家？要是像剛剛在半路睡著就麻煩了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"밤...?","JPN":"夜……？","ENG":"Night...?","TWN":"天黑……？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"밤이라 함은, 황금나무의 예언에 나오는 그것을 말씀하시는 것이옵니까?","JPN":"夜というのは、黄金の木の予言に出てくるあれのことでしょうか？","ENG":"By night, do you mean the one spoken of in the prophecy of the Golden Tree?","TWN":"你說的天黑，是黃金樹的預言裡的那個嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"황금나무의 예언? 그게 무슨 소리야? 해가 저물면 밤이 되는 게 이상해?","JPN":"黄金の木の予言？　どういうこと？　日が暮れると夜になるのが変なことなの？","ENG":"The prophecy of the Golden Tree? What do you mean? Isn't it normal for night to come when the sun sets?","TWN":"黃金樹的預言？那是什麼意思？太陽下山就會天黑，很奇怪嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"앗! 벌써 시간이...!","JPN":"あっ、もうこんな時間……！","ENG":"Ah! It's already this late...!","TWN":"啊！時間這麼晚了……！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"조금 있으면 일출 기도가 있기에, 이만 돌아가겠나이다.","JPN":"もうすぐ日の出のお祈りが始まりますので、この辺で失礼いたします。","ENG":"The sunrise prayer will begin soon, so I must return now.","TWN":"馬上就要日出禱告了，我先回去了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"이곳 낙원엔 우리가 알던 밤이 없단다.","JPN":"この楽園に、私たちの知っていた夜はないのよ。","ENG":"In the Promised Land, the night we once knew does not exist.","TWN":"這個樂園沒有我們認知的夜晚。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"해가 저물면, 다시 새로운 해가 떠오르지.","JPN":"日が暮れると、また新しい日が昇るの。","ENG":"When the sun sets, a new sun rises again.","TWN":"太陽下山，又會有新的太陽升起。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"왜 그런 거죠?","JPN":"どうして？","ENG":"Why is that?","TWN":"為什麼呢？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"이 낙원은 아직 완성된 게 아니거든.","JPN":"この楽園はまだ未完成だからよ。","ENG":"Because the Promised Land is not yet complete.","TWN":"這個樂園還沒完成。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그래서 이곳 사람들은 천사가 밤을 이끌고 내려오는 날, 비로소 낮과 밤이 공존하며 그들의 낙원이 완벽해질 거라고 믿고 있지.","JPN":"だからここの人たちは天使が夜を連れて降りて来る日、初めて昼と夜が共存し、彼らの楽園が完璧になると信じているわ。","ENG":"So the people here believe that when the day comes when an angel descends bringing the night, day and night will finally coexist, and the Promised Land will become perfect.","TWN":"所以這裡的人相信天使帶來夜晚的那天，白天與黑夜同時存在，他們的樂園才會完美。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그것이 황금나무의 예언이란다.","JPN":"それが黄金の木の予言なの。","ENG":"That is the prophecy of the Golden Tree.","TWN":"那就是黃金樹的預言。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"천사...?","JPN":"天使……？","ENG":"An angel...?","TWN":"天使……？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런 게 진짜 있는 거였구나.","JPN":"そんなもの、本当に存在してるんだ。","ENG":"So such a thing really exists.","TWN":"原來真的存在啊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"침몰하는 천지의 중심에서, 그루터기만 남은 황금나무가 빛을 발하니-","JPN":"沈没する天地の中心で、切り株だけになった黄金の木が光を放つと……","ENG":"At the center of the sinking heavens and earth, the Golden Tree that remained only as a stump shone with light...","TWN":"在沉沒的天地中心，只剩下木墩的黃金樹綻放光芒－"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"세상을 가득 메우던 겨울이 불현듯 물러나고... 봄이 도래했습니다.","JPN":"世界を埋め尽くしていた冬は突如として終わり……春が訪れました。","ENG":"The winter that once filled the world suddenly retreated... and spring arrived.","TWN":"覆蓋世界的冬天突然退去……春天來臨。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"계절 함께 자라난 새순, 땅의 온갖 것이 수확할 만큼 여무는 가을 무렵.","JPN":"季節とともに芽吹いた新芽、大地に育つすべてが収穫の時期を迎える秋頃。","ENG":"By autumn, when the new sprouts that grew with the seasons had matured enough for all the land's bounty to be harvested,","TWN":"伴隨季節長出的新芽，收獲著大地一切的秋天。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>그녀</color>는 한 폭의 그림처럼 세월을 담아, 오늘의 낙원을 만들었습니다.","JPN":"<color=#ffd34c>彼女</color>はまるで一枚の絵のごとく月日を閉じ込め、今の楽園を作りました。","ENG":"<color=#ffd34c>She</color>, carrying the passage of time like a painting, created today's Promised Land.","TWN":"<color=#ffd34c>她</color>就像一幅畫融入歲月，創造了今天的樂園。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그렇기에 우리는 기도합니다.","JPN":"ですから、我らは祈るのです。","ENG":"And so we pray...","TWN":"所以我們開始祈禱。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"한 차례 잃어버린 현실을 우리 품에 돌려주고, 낙원의 완성이라는 이상을 꿈꾸게 해준...","JPN":"一度は失った現実を再び我らに与え、楽園の完成という理想を夢見ることができるようにしてくれた……","ENG":"For the one who returned the reality we once lost to our arms and allowed us to dream of the ideal called the completion of the Promised Land...","TWN":"重拾失去的現實，讓我們夢想著完成樂園……"},"stage":{"bg":"CHURCH","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그녀</color>를 위해.","JPN":"<color=#ffd34c>彼女</color>のために。","ENG":"We pray for <color=#ffd34c>her</color>.","TWN":"為了<color=#ffd34c>她</color>。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"...기도합니다.","JPN":"……お祈りします。","ENG":"...We pray.","TWN":"……祈禱。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"CITIZEN_ROOT_NPC_NULL","text":{"KOREA":"이렇게 열심히 살아가다 보면 이 낙원에도 밤이 오겠지요?","JPN":"こうやって懸命に生きていれば、この楽園にも夜が訪れるでしょうか。","ENG":"If we keep living diligently like this, night will come to the Promised Land someday, won't it?","TWN":"如果這麼努力生活，這個樂園也會迎來夜晚吧？"},"stage":{"bg":"CHURCH","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"물론입니다. 그날이 오면 우리 모두의 소망도 이루어지겠죠.","JPN":"もちろんです。その日が来れば私たちの願いも叶えられるでしょう。","ENG":"Of course. When that day comes, all our wishes will be fulfilled as well.","TWN":"當然。到了那一天，我們所有的願望都會實現。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"황금나무의 목소리가 그렇게 예언했으니까요.","JPN":"黄金の木の声がそう予言したのですから。","ENG":"The voice of the Golden Tree prophesied it so.","TWN":"黃金樹的聲音是這麼預言的。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"궁금한 것이 있사옵니다, 아버지.","JPN":"質問がございます、お父様。","ENG":"There is something I wish to ask, Father.","TWN":"父親，我有個問題。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"뭐가 궁금하니? 에클레시아.","JPN":"何が知りたいんだい？　エクレシア。","ENG":"What is it you wish to know, Ecclesia?","TWN":"什麼問題，艾可露西亞？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원이 완성되기 위해선 어째서 밤이 필요한 것이옵니까?","JPN":"楽園が完成するためには、どうして夜が必要なのでございますか？","ENG":"Why must night exist for the Promised Land to be complete?","TWN":"為什麼需要夜晚完成樂園？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저희는 어둠이 없어도 이토록 잘 살아가고 있는데 말입니다.","JPN":"わたくしたちは闇がなくてもこのように問題なく生きております。","ENG":"We are living perfectly well even without darkness.","TWN":"我們即使沒有黑暗，也過得很好啊。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"모든 것엔 양면이 있어야 하는 법이니까.","JPN":"すべてには両面が必要だからね。","ENG":"Everything must have two sides.","TWN":"因為萬物都有兩面性。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"어둠 없이 빛만이 존재하는 세상은 반쪽짜리일 뿐이기 때문이란다.","JPN":"闇がなく光だけが存在している世界は不完全なんだよ。","ENG":"A world where only light exists without darkness is only half complete.","TWN":"沒有黑暗只有光的世界，只是一半的世界而已。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그렇다면...","JPN":"ならば……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원에 죽음이 없는 것도 그런 이유이옵니까?","JPN":"楽園に死がないのも、そのような理由からですか？","ENG":"Is the reason there is no death in the Promised Land the same?","TWN":"樂園沒有死亡也是這個原因嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그건...","JPN":"それは……","ENG":"That is...","TWN":"那個……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"더 이상 누구도 죽길 바라지 않았던 어떤 <color=#ffd34c>의지</color>란다.","JPN":"もう誰も死なないことを願っていたある種の<color=#ffd34c>意志</color>なんだよ。","ENG":"Because of a certain <color=#ffd34c>will</color> that wished for no one to die ever again.","TWN":"那是……不希望再有人死去的某種<color=#ffd34c>意志</color>。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"하지만 낙원이 완벽해지기 위해선, 언젠가 그 죽음 또한 필요해지겠지.","JPN":"でも楽園を完璧なものにするためには、いつかその死も必要となるだろうね。","ENG":"But for the Promised Land to become perfect, someday even that death will become necessary.","TWN":"但為了讓樂園完美，終有一天，也會需要死亡。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원이 완벽해진다는 게 어떤 의미인지, 아직도 잘 모르겠사옵니다.","JPN":"楽園を完璧なものにするというのがどういう意味なのか、まだよく分かりません。","ENG":"I still don't quite understand what it means for the Promised Land to become perfect.","TWN":"我還是不太明白，樂園完美到底是什麼意思。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"완벽이란 말 자체엔 아무런 의미도 없단다.","JPN":"完璧という言葉自体には何の意味もない。","ENG":"The word perfection itself has no meaning.","TWN":"完美這個詞本身沒有意義。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그것을 정의하고 추구하려는 것 자체가 불완전하고, 상대적이기 때문이지.","JPN":"それを定義し追及しようとすること自体が不完全であり、相対的だからだ。","ENG":"Because defining it and striving for it is itself imperfect and relative.","TWN":"去定義並追求它本身就是不完美的，因為它們是相對的。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그렇기 때문에 모든 존재는 완벽해지고 싶은 욕망을 가지고 살아가는 거야.","JPN":"だからこそ、すべての存在は完璧になりたいという欲望を抱いて生きているんだよ。","ENG":"That is why all beings live with the desire to become perfect.","TWN":"所以所有存在才會懷抱想變完美的欲望活著。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"한 차례 종말을 경험했기에- 누구보다 살아가고 싶고, 복수하길 바라는 낙원의 주민들처럼.","JPN":"一度終末を経験したからこそ……誰よりも生きたいし、復讐したいと願う楽園の住民たちのようにね。","ENG":"Just like the residents of the Promised Land, who experienced the end of the world once and now wish to live more than anyone else... and to take revenge.","TWN":"因為經歷過一次末日－所以他們像樂園居民一樣比誰都想活下去，也渴望復仇。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원의 사람들에게 완벽은... 복수인 것이옵니까?","JPN":"楽園の人々にとって完璧とは……復讐なのですか？","ENG":"For the people of the Promised Land... does perfection mean revenge?","TWN":"對樂園的人來說，完美……就是復仇嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"우리는 언젠가 이 낙원에 밤이 오길 기다리지.","JPN":"僕たちはいつかはこの楽園に訪れる夜を待っているんだ。","ENG":"We are waiting for the day when night comes here.","TWN":"我們一直等待樂園迎來夜晚。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"우리의 오랜 정적을 우리 손으로 죽일 것이라는, 황금나무의 예언을 완성하기 위해.","JPN":"古い政敵を自分たちの手で殺すだろうという、黄金の木の予言を完成するために。","ENG":"To fulfill the prophecy of the Golden Tree that says we will kill our ancient foe with our own hands.","TWN":"為了完成黃金樹的預言，親手終結我們長久的敵人。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"우리 고향을 멸망시킨, 마왕 타기리온에게 복수할 순간을 위해.","JPN":"僕たちの故郷を滅亡させた、魔王タギリオンに復讐する瞬間のためにね。","ENG":"For the moment when we take revenge on the Demon Lord Thagirion who destroyed our homeland.","TWN":"為了向毀滅我們故鄉的魔王塔基里翁復仇。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"소녀는 낙원의 주민이오나...","JPN":"わたくしは楽園の住民でございますが……","ENG":"Though I am a resident of the Promised Land...","TWN":"我是樂園的居民……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"복수란 것이 낙원을 완벽하게 만들어준다고 생각하지 않사옵니다.","JPN":"復讐というものが楽園を完璧にしてくれるとは思いません。","ENG":"I don't believe revenge will make the Promised Land perfect.","TWN":"但我不認為復仇能讓樂園完美。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그 마음은 이해한다, 에클레시아.","JPN":"その気持ちは分かるよ、エクレシア。","ENG":"I understand how you feel, Ecclesia.","TWN":"我明白你的心情，艾可露西亞。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"너는 줄곧, 그 어떤 다툼도 없는 평화로운 낙원을 원해왔으니까.","JPN":"エクレシアはずっと、争いのない平和な楽園を求めてきたから。","ENG":"You have always wished for a peaceful Promised Land with no conflicts.","TWN":"你一直希望想要沒有爭鬥的和平樂園。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"복수니, 원망이니 하는 거친 표현은 너에겐 어울리지도, 완벽하지도 않지.","JPN":"復讐だの恨みだのといった乱暴な表現はお前には似合わないし、完璧でもない。","ENG":"Harsh words like revenge or resentment do not suit you, nor would they be perfect.","TWN":"復仇、怨恨這種負面的情緒，不適合你，也不完美。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그러니 넌 이곳에서 편히 쉬도록 하렴.","JPN":"だからお前はここでゆっくり休みなさい。","ENG":"So rest here in peace.","TWN":"所以你就在這裡安心休息吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"언제나 그렇듯, 낙원이 네 소망을 이뤄줄 테니.","JPN":"今までそうだったように、楽園がお前の願いを叶えてくれるはずだ。","ENG":"As always, the Promised Land will fulfill your wish.","TWN":"樂園會像往常一樣，實現你的願望。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};